ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/banking#>
PREFIX p: <http://ambrosia.example.org/banking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  full: { SELECT ?name ?name2 ?bank_name WHERE {
  ?l a :City .
  ?b a :Banks .
  ?b p:hasCity ?l .
  ?c a :Country .
  ?b p:hasCountry ?c .
  ?c p:name ?name .
  ?l p:name ?name2 .
  ?b p:bank_name ?bank_name .
} }
  component: { SELECT ?name ?bank_name WHERE {
  ?l a :City .
  ?b a :Banks .
  ?b p:hasCity ?l .
  ?l p:name ?name .
  ?b p:bank_name ?bank_name .
} }
  component_2: { SELECT ?name ?bank_name WHERE {
  ?l a :Country .
  ?b a :Banks .
  ?b p:hasCountry ?l .
  ?l p:name ?name .
  ?b p:bank_name ?bank_name .
} }
}
